   SET facilitis_nm = #{facilitisNm}
     , ord_seq = #{ordSeq}
     , use_yn = #{useYn}
     , facilitis_desc = #{facilitisDesc}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE facilitis_id = #{facilitisId}
   AND comp_id = #{compId}

